protected static int[] computeLineBreaks(String text) {
		// initially we assume an average of 20 chars per line
		List<Integer> list = Lists.newArrayListWithExpectedSize(text.length() / 20 + 1);
		char ch;
		int length= text.length();
		for (int i= 0; i < length; i++) {
			ch= text.charAt(i);
			if (ch == '\r') {
				list.add(i);
				if (i + 1 < length) {
					if (text.charAt(i + 1) == '\n') {
						i++;
					}
				}
			} else if (ch == '\n') {
				list.add(i);
			}
		}
		int[] result = new int[list.size()];
		for(int i = 0; i < result.length; i++) {
			result[i] = list.get(i).intValue();
		}
		return result;
	}

prediction:
private static int[] computeLineBreaks(String text) {
		int[] lineBreaks = new int[text.length()];
		int lineBreakCount = 0;
		int lineBreakOffset = 0;
		for (int i = 0; i < text.length(); i++) {
			char c = text.charAt(i);
			if (c == '\r') {
				lineBreaks[lineBreakCount++] = lineBreakOffset;
				lineBreakOffset = i + 1;
				if (i + 1 < text.length() && text.charAt(i + 1) == '\n') {
					i++;
				}
			} else if (c == '\n') {
				lineBreaks[lineBreakCount++] = lineBreakOffset;
				lineBreakOffset = i + 1;
			}
		}
		lineBreaks[lineBreakCount++] = lineBreakOffset;
		return Arrays.copyOf(lineBreaks, lineBreakCount);
	}

