boolean isOnCooldown(ItemStack item, LastEaten lastEaten) {
            final Optional<Instant> newestEatTime = lastEaten.getForItem(item);
            if (newestEatTime.isPresent()) {
                final long cooldown = getCooldownForItem(item);
                final long timeElapsedSinceEaten = Duration.between(newestEatTime.get(), Instant.now()).getSeconds();
                return timeElapsedSinceEaten < cooldown;
            }
            return false;
        }

