target:
private static byte[] hex2bin(String hex) {
        int i;
        int len = hex.length();
        byte[] data = new byte [len / 2];
        for (i = 0; i < len; i += 2) {
            data[i / 2] = (byte)((Character.digit(hex.charAt(i), 16) << 4) +
                    Character.digit(hex.charAt(i + 1), 16));
        }
        return data;
    }

prediction:
private static byte[] hex2bin(String hexStr) {
        byte[] result = null;
        if (hexStr!= null) {
            result = new byte[hexStr.length() / 2];
            for (int i = 0; i < result.length; i++) {
                result[i] = (byte) Integer.parseInt(hexStr.substring(i * 2,
                        i * 2 + 2), 16);
            }
        }

        return result;
    }

