target:
private boolean isComponentPartOfCurrentMenu(MenuElement root,Component c) {
        MenuElement children[];
        int i,d;

        if (root == null)
            return false;

        if(root.getComponent() == c)
            return true;
        else {
            children = root.getSubElements();
            for(i=0,d=children.length;i<d;i++) {
                if(isComponentPartOfCurrentMenu(children[i],c))
                    return true;
            }
        }
        return false;
    }

prediction:
public boolean isComponentPartOfCurrentMenu(MenuElement me, Component c) {
        MenuElement[] subs = me.getSubElements();
        for (int i=0; i<subs.length; i++) {
            if (subs[i] == null ||!subs[i].getComponent().isShowing()
                ||!subs[i].getComponent().isEnabled()) {
                continue;
            }
            if (subs[i].getComponent() == c) {
                return true;
            }
        }
        return false;
    }

