public ContentValues getBLUETOOTH_STATE() {
        int bluetoothState = 0;
        String name;
        // If APK < KITKAT Settings.Secure.LOCATION_PROVIDERS_ALLOWED
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.KITKAT) {
            name = "bluetooth_state";

            String providers = Settings.Secure.getString(this.getContentResolver(), Settings.Secure.BLUETOOTH_ON);
            if (TextUtils.isEmpty(providers)) {
                bluetoothState = 0;
            } else {
                if (providers.contains("1")) {
                    bluetoothState = 1;
                }
            }
        }
        // If APK >= KITKAT Settings.Secure.LOCATION_MODE
        else {
            name = "bluetooth_state";

            try {
                bluetoothState = Settings.Secure.getInt(this.getContentResolver(),
                        Settings.Secure.BLUETOOTH_ON);
            } catch (Settings.SettingNotFoundException e) {
                e.printStackTrace();
                bluetoothState = 0;
            }
        }
        ContentValues cv = new ContentValues(3);
        cv.put(DBHandler.COLUMN_SETTING, name);
        cv.put(DBHandler.COLUMN_INITIAL, bluetoothState);
        cv.put(DBHandler.COLUMN_TYPE, 2);
        return cv;
    }

