target:
public ServiceContext get(Integer id)
    {
        Object result = scMap.get(id);
        if (result == null)
            return null ;

        // Lazy unmarshaling on first use.
        if (result instanceof byte[]) {

            ServiceContext sc = unmarshal(id, (byte[])result);

            scMap.put(id, sc);

            return sc;
        } else {
            return (ServiceContext)result;
        }
    }

prediction:
public ServiceContext get(Integer id) {
        ServiceContext sc = (ServiceContext)scMap.get(id);

        if (sc == null) {
            if (orb.serviceContextDebugFlag)
                dprint("Service context " + id + " not found in map");

            byte[] data = (byte[])scMap.get(id);

            if (data == null) {
                if (orb.serviceContextDebugFlag)
                    dprint("Service context " + id + " not found in map");

                return null;
            }

            sc = unmarshal(id, data);

            if (sc == null)
                throw wrapper.svcctxUnmarshalError(
                    CompletionStatus.COMPLETED_MAYBE);

            scMap.put(id, sc);
        }

        return sc;
    }

